SELECT whitelist_id AS whitelistId, whitelist_type AS whitelistType, CASE whitelist_type WHEN 1 THEN '邮箱' WHEN 2 THEN '手机号' ELSE '未知' END AS whitelistTypeDesc, whitelist_value AS whitelistValue, whitelist_desc AS whitelistDesc, status, CASE status WHEN 0 THEN '禁用' WHEN 1 THEN '启用' ELSE '未知' END AS statusDesc, creator_name AS creatorName, c_time AS cTime FROM sys_user_whitelist WHERE is_del = 0
AND whitelist_type = #{whitelistType}
AND whitelist_value LIKE CONCAT('%', #{whitelistValue}, '%')
AND status = #{status}
ORDER BY c_time DESC LIMIT #{pageIndex}, #{pageSize}

SELECT COUNT(*)
FROM sys_user_whitelist
WHERE is_del = 0

    AND whitelist_type = #{whitelistType}


    AND whitelist_value LIKE CONCAT('%', #{whitelistValue}, '%')


    AND status = #{status}

SELECT COUNT(*)
FROM sys_user_whitelist
WHERE whitelist_type = #{whitelistType}
  AND whitelist_value = #{whitelistValue}
  AND status = 1
  AND is_del = 0
